import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useFavorites } from '../context/FavoritesContext';
import './ListingCard.css';

function ListingCard({ listing }) {
  const { user } = useAuth();
  const { isFavorite, addFavorite, removeFavorite } = useFavorites();
  const favorite = isFavorite(listing.listing_id);

  const handleFavoriteClick = async (e) => {
    e.preventDefault();
    if (!user) {
      alert('Войдите чтобы добавлять в избранное');
      return;
    }

    if (favorite) {
      await removeFavorite(user.user_id, listing.listing_id);
    } else {
      await addFavorite(user.user_id, listing.listing_id);
    }
  };

  return (
    <div className="listing-card">
      <Link to={`/listing/${listing.listing_id}`}>
        <div className="card-image">
          <img
            src={listing.photos?.[0]?.file_url || '/no-image.jpg'}
            alt={listing.title}
          />
          <button
            className={`favorite-btn ${favorite ? 'active' : ''}`}
            onClick={handleFavoriteClick}
          >
            {favorite ? '★' : '☆'}
          </button>
        </div>

        <div className="card-content">
          <h3 className="card-title">{listing.title}</h3>
          <p className="card-price">
            {listing.price?.toLocaleString()} ₽
          </p>
          <p className="card-address">
            📍 {listing.address}
          </p>
          <div className="card-details">
            <span>📐 {listing.total_area} м²</span>
            {listing.rooms && <span>🛏 {listing.rooms} комн</span>}
          </div>
          <p className="card-date">
            📅 {new Date(listing.publication_date).toLocaleDateString()}
          </p>
        </div>
      </Link>
    </div>
  );
}

export default ListingCard;
